import{_ as o,o as t,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"11A. Consultation About Changes To Rosters Or Hours Of Work","description":"","frontmatter":{"title":"11A. Consultation About Changes To Rosters Or Hours Of Work","eba":"Nurses and Midwives 2024-2028","topics":["hours","rosters","consultation"]},"headers":[],"relativePath":"ebas/nurses-midwives/consultation-disputes/11A-consultation-about-changes-to-rosters-or-hours-of-work.md","filePath":"ebas/nurses-midwives/consultation-disputes/11A-consultation-about-changes-to-rosters-or-hours-of-work.md"}'),n={name:"ebas/nurses-midwives/consultation-disputes/11A-consultation-about-changes-to-rosters-or-hours-of-work.md"};function a(i,e,l,h,p,u){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_11a-consultation-about-changes-to-rosters-or-hours-of-work" tabindex="-1">11A. Consultation About Changes To Rosters Or Hours Of Work <a class="header-anchor" href="#_11a-consultation-about-changes-to-rosters-or-hours-of-work" aria-label="Permalink to &quot;11A. Consultation About Changes To Rosters Or Hours Of Work&quot;">​</a></h1><p>This clause 11A applies where a change to regular rosters or ordinary hours of work (which may impact upon an Employee, particularly in relation to their family and caring responsibilities) does not constitute a ‘Major Change’ in accordance with subclause 11.2(c).</p><p><strong>11A.1</strong> Where an Employer proposes to change an Employee&#39;s regular roster or ordinary hours of work, the Employer must:</p><p><strong>(a)</strong> notify the relevant employee or employees of the proposed change; and</p><p><strong>(b)</strong> consult with the relevant employee or employees and their representative/s, if any, about the proposed change as described below.</p><p><strong>11A.2</strong> As soon as practicable after proposing to introduce the change, the Employer must:</p><p><strong>(a)</strong> discuss with the relevant employee/s the introduction of the change, and</p><p><strong>(c)</strong> for the purposes of the discussion, provide to the relevant employee/s all relevant information about the change, including:</p><p><strong>(i)</strong> the nature of the change and when that change is proposed to commence; and</p><p><strong>(ii)</strong> information about what the Employer reasonably believes will be the effects of the change on the relevant employees; and</p><p><strong>(iii)</strong> information about any other matters that the Employer reasonably believes are likely to affect the relevant employees; and</p><p><strong>(d)</strong> invite the relevant employees to give their views about the impact of the change (including any impact in relation to their family or caring responsibilities).</p><p><strong>11A.3</strong> However, the Employer is not required to disclose confidential or commercially sensitive information to the relevant employees.</p><p><strong>11A.4</strong> The Employer must give prompt and genuine consideration to matters raised about the change by the relevant employees and consider health and safety impacts including fatigue.</p><p><strong>11A.5</strong> In this term relevant employees means the Employee or Employees who may be affected by a change referred to in clause 11A.1.</p><p><strong>11A.6</strong> The requirement to consult under this clause 11A does not apply to an Employee where the change to an Employee&#39;s regular roster or ordinary hours of work is as a consequence of that Employee&#39;s irregular, sporadic or unpredictable working hours, self-rostering or, where permitted, a rotating roster.</p><p><strong>11A.7</strong> The provisions of this clause 11A are to be read in conjunction with the terms of the engagement between the Employer and Employee, and other Agreement provisions concerning the scheduling of work and notice requirements.</p><p>Plain language terms: rostering, shift roster, duty roster, roster changes.</p>',18)])])}const m=o(n,[["render",a]]);export{g as __pageData,m as default};
